   232	mod tests {
   233	    use super::*;
   234	
   235	    #[test]
   236	    fn try_open_path_best_effort_returns_none_for_missing_path() {
   237	        let result = try_open_path(
   238	            &PathBuf::from("/nonexistent/openshell/test/path"),
   239	            &LandlockCompatibility::BestEffort,
   240	        );
   241	        assert!(result.is_ok());
   242	        assert!(result.unwrap().is_none());
   243	    }
   244	
   245	    #[test]
   246	    fn try_open_path_hard_requirement_errors_for_missing_path() {
   247	        let result = try_open_path(
   248	            &PathBuf::from("/nonexistent/openshell/test/path"),
   249	            &LandlockCompatibility::HardRequirement,
   250	        );
   251	        assert!(result.is_err());
   252	        let err_msg = result.unwrap_err().to_string();
   253	        assert!(
   254	            err_msg.contains("hard_requirement"),
   255	            "error should mention hard_requirement mode: {err_msg}"
   256	        );
   257	        assert!(
   258	            err_msg.contains("does not exist"),
   259	            "error should include the classified reason: {err_msg}"
   260	        );
   261	    }
   262	
   263	    #[test]
   264	    fn try_open_path_succeeds_for_existing_path() {
   265	        let dir = tempfile::tempdir().unwrap();
   266	        let result = try_open_path(dir.path(), &LandlockCompatibility::BestEffort);
   267	        assert!(result.is_ok());
   268	        assert!(result.unwrap().is_some());
   269	    }
   270	
   271	    #[test]
   272	    fn classify_not_found() {
   273	        let err = std::io::Error::from_raw_os_error(libc::ENOENT);
   274	        assert_eq!(classify_io_error(&err), "path does not exist");
   275	    }
   276	
   277	    #[test]
   278	    fn classify_permission_denied() {
   279	        let err = std::io::Error::from_raw_os_error(libc::EACCES);
   280	        assert_eq!(classify_io_error(&err), "permission denied");
   281	    }
   282	
   283	    #[test]
   284	    fn classify_symlink_loop() {
   285	        let err = std::io::Error::from_raw_os_error(libc::ELOOP);
   286	        assert_eq!(classify_io_error(&err), "too many symlink levels");
   287	    }
   288	
   289	    #[test]
   290	    fn classify_name_too_long() {
   291	        let err = std::io::Error::from_raw_os_error(libc::ENAMETOOLONG);
   292	        assert_eq!(classify_io_error(&err), "path name too long");
   293	    }
   294	
   295	    #[test]
   296	    fn classify_not_a_directory() {
   297	        let err = std::io::Error::from_raw_os_error(libc::ENOTDIR);
   298	        assert_eq!(classify_io_error(&err), "path component is not a directory");
   299	    }
   300	
   301	    #[test]
   302	    fn classify_unknown_error() {
   303	        let err = std::io::Error::from_raw_os_error(libc::EIO);
   304	        assert_eq!(classify_io_error(&err), "unexpected error");
   305	    }
   306	
   307	    #[test]
   308	    fn classify_path_fd_error_extracts_io_error() {
   309	        // Use PathFd::new on a non-existent path to get a real PathFdError
   310	        // (the OpenCall variant is #[non_exhaustive] and can't be constructed directly).
   311	        let err = PathFd::new("/nonexistent/openshell/classify/test").unwrap_err();
   312	        assert_eq!(classify_path_fd_error(&err), "path does not exist");
   313	    }
   314	}
