   243	        )))]
   244	        {
   245	            nix::unistd::initgroups(user_cstr.as_c_str(), group.gid).into_diagnostic()?;
   246	        }
   247	    }
   248	
   249	    nix::unistd::setgid(group.gid).into_diagnostic()?;
   250	
   251	    // Verify effective GID actually changed (defense-in-depth, CWE-250 / CERT POS37-C)
   252	    let effective_gid = nix::unistd::getegid();
   253	    if effective_gid != group.gid {
   254	        return Err(miette::miette!(
   255	            "Privilege drop verification failed: expected effective GID {}, got {}",
   256	            group.gid,
   257	            effective_gid
   258	        ));
   259	    }
   260	
   261	    if user_name.is_some() {
   262	        nix::unistd::setuid(user.uid).into_diagnostic()?;
   263	
   264	        // Verify effective UID actually changed (defense-in-depth, CWE-250 / CERT POS37-C)
   265	        let effective_uid = nix::unistd::geteuid();
   266	        if effective_uid != user.uid {
   267	            return Err(miette::miette!(
   268	                "Privilege drop verification failed: expected effective UID {}, got {}",
   269	                user.uid,
   270	                effective_uid
   271	            ));
   272	        }
   273	
   274	        // Verify root cannot be re-acquired (CERT POS37-C hardening).
   275	        // If we dropped from root, setuid(0) must fail; success means privileges
   276	        // were not fully relinquished.
   277	        if nix::unistd::setuid(nix::unistd::Uid::from_raw(0)).is_ok() && user.uid.as_raw() != 0 {
   278	            return Err(miette::miette!(
   279	                "Privilege drop verification failed: process can still re-acquire root (UID 0) \
   280	                 after switching to UID {}",
   281	                user.uid
   282	            ));
   283	        }
   284	    }
   285	
   286	    Ok(())
   287	}
