   296	impl ProcessStatus {
   297	    /// Get the exit code, or 128 + signal number if killed by signal.
   298	    #[must_use]
   299	    pub fn code(&self) -> i32 {
   300	        self.code
   301	            .or_else(|| self.signal.map(|s| 128 + s))
   302	            .unwrap_or(-1)
   303	    }
   304	
   305	    /// Check if the process exited successfully.
   306	    #[must_use]
   307	    pub fn success(&self) -> bool {
   308	        self.code == Some(0)
   309	    }
   310	
   311	    /// Get the signal that killed the process, if any.
   312	    #[must_use]
   313	    pub const fn signal(&self) -> Option<i32> {
   314	        self.signal
   315	    }
   316	}
