    49	fn build_filter(allow_inet: bool) -> Result<seccompiler::BpfProgram> {
    50	    let mut rules: BTreeMap<i64, Vec<SeccompRule>> = BTreeMap::new();
    51	
    52	    // --- Socket domain blocks ---
    53	    let mut blocked_domains = vec![libc::AF_PACKET, libc::AF_BLUETOOTH, libc::AF_VSOCK];
    54	    if !allow_inet {
    55	        blocked_domains.push(libc::AF_INET);
    56	        blocked_domains.push(libc::AF_INET6);
    57	        blocked_domains.push(libc::AF_NETLINK);
    58	    }
    59	
    60	    for domain in blocked_domains {
    61	        debug!(domain, "Blocking socket domain via seccomp");
    62	        add_socket_domain_rule(&mut rules, domain)?;
    63	    }
    64	
    65	    // --- Unconditional syscall blocks ---
    66	    // These syscalls are blocked entirely (empty rule vec = unconditional EPERM).
    67	
    68	    // Fileless binary execution via memfd bypasses Landlock filesystem restrictions.
    69	    rules.entry(libc::SYS_memfd_create).or_default();
    70	    // Cross-process memory inspection and code injection.
    71	    rules.entry(libc::SYS_ptrace).or_default();
    72	    // Kernel BPF program loading.
    73	    rules.entry(libc::SYS_bpf).or_default();
    74	    // Cross-process memory read.
    75	    rules.entry(libc::SYS_process_vm_readv).or_default();
    76	    // Async I/O subsystem with extensive CVE history.
    77	    rules.entry(libc::SYS_io_uring_setup).or_default();
    78	    // Filesystem mount could subvert Landlock or overlay writable paths.
    79	    rules.entry(libc::SYS_mount).or_default();
    80	
    81	    // --- Conditional syscall blocks ---
    82	
    83	    // execveat with AT_EMPTY_PATH enables fileless execution from an anonymous fd.
    84	    add_masked_arg_rule(
    85	        &mut rules,
    86	        libc::SYS_execveat,
    87	        4, // flags argument
    88	        libc::AT_EMPTY_PATH as u64,
    89	    )?;
    90	
    91	    // unshare with CLONE_NEWUSER allows creating user namespaces to escalate privileges.
    92	    add_masked_arg_rule(
    93	        &mut rules,
    94	        libc::SYS_unshare,
    95	        0, // flags argument
    96	        libc::CLONE_NEWUSER as u64,
    97	    )?;
    98	
    99	    // seccomp(SECCOMP_SET_MODE_FILTER) would let sandboxed code replace the active filter.
   100	    let condition = SeccompCondition::new(
   101	        0, // operation argument
   102	        SeccompCmpArgLen::Dword,
   103	        SeccompCmpOp::Eq,
   104	        SECCOMP_SET_MODE_FILTER,
   105	    )
   106	    .into_diagnostic()?;
   107	    let rule = SeccompRule::new(vec![condition]).into_diagnostic()?;
   108	    rules.entry(libc::SYS_seccomp).or_default().push(rule);
   109	
   110	    let arch = std::env::consts::ARCH
   111	        .try_into()
   112	        .map_err(|_| miette::miette!("Unsupported architecture for seccomp"))?;
   113	
   114	    let filter = SeccompFilter::new(
   115	        rules,
   116	        SeccompAction::Allow,
   117	        SeccompAction::Errno(libc::EPERM as u32),
   118	        arch,
   119	    )
   120	    .into_diagnostic()?;
   121	
   122	    filter.try_into().into_diagnostic()
   123	}
