   126	fn add_socket_domain_rule(rules: &mut BTreeMap<i64, Vec<SeccompRule>>, domain: i32) -> Result<()> {
   127	    let condition =
   128	        SeccompCondition::new(0, SeccompCmpArgLen::Dword, SeccompCmpOp::Eq, domain as u64)
   129	            .into_diagnostic()?;
   130	
   131	    let rule = SeccompRule::new(vec![condition]).into_diagnostic()?;
