   136	/// Block a syscall when a specific bit pattern is set in an argument.
   137	///
   138	/// Uses `MaskedEq` to check `(arg & flag_bit) == flag_bit`, which triggers
   139	/// EPERM when the flag is present regardless of other bits in the argument.
   140	fn add_masked_arg_rule(
   141	    rules: &mut BTreeMap<i64, Vec<SeccompRule>>,
   142	    syscall: i64,
   143	    arg_index: u8,
   144	    flag_bit: u64,
   145	) -> Result<()> {
   146	    let condition = SeccompCondition::new(
   147	        arg_index,
   148	        SeccompCmpArgLen::Dword,
   149	        SeccompCmpOp::MaskedEq(flag_bit),
   150	        flag_bit,
   151	    )
   152	    .into_diagnostic()?;
   153	    let rule = SeccompRule::new(vec![condition]).into_diagnostic()?;
   154	    rules.entry(syscall).or_default().push(rule);
   155	    Ok(())
   156	}
