//! Platform sandboxing implementation.

use crate::policy::SandboxPolicy;
use miette::Result;

#[cfg(target_os = "linux")]
pub mod linux;

#[cfg(target_os = "linux")]
pub use linux::BuiltRuleset;

/// Apply sandboxing rules for the current platform.
///
/// # Errors
///
/// Returns an error if the sandbox cannot be applied.
#[cfg_attr(not(target_os = "linux"), allow(clippy::unnecessary_wraps))]
pub fn apply(policy: &SandboxPolicy, workdir: Option<&str>) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        linux::apply(policy, workdir)
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (policy, workdir);
        openshell_ocsf::ocsf_emit!(
            openshell_ocsf::DetectionFindingBuilder::new(crate::ocsf_ctx())
                .activity(openshell_ocsf::ActivityId::Open)
                .severity(openshell_ocsf::SeverityId::Medium)
                .finding_info(openshell_ocsf::FindingInfo::new(
                    "platform-sandbox-unavailable",
                    "Platform Sandboxing Not Implemented",
                ).with_desc("Sandbox policy provided but platform sandboxing is not yet implemented on this OS"))
                .message("Platform sandboxing not yet implemented")
                .build()
        );
        Ok(())
    }
}

/// Build a Landlock ruleset (Linux only). Returns `None` on non-Linux
/// or when the policy lists no paths to protect.
///
/// Must be called while the process still has sufficient privileges (root).
/// Call [`enforce`] afterward to activate restrictions.
#[cfg_attr(not(target_os = "linux"), allow(clippy::unnecessary_wraps))]
pub fn build_ruleset(policy: &SandboxPolicy, workdir: Option<&str>) -> Result<Option<BuiltRuleset>> {
    #[cfg(target_os = "linux")]
    {
        linux::build_ruleset(policy, workdir)
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (policy, workdir);
        Ok(None)
    }
}

/// Enforce a previously built Landlock ruleset and apply seccomp (Linux only).
///
/// Call this after [`build_ruleset`] and after dropping privileges.
#[cfg_attr(not(target_os = "linux"), allow(clippy::unnecessary_wraps))]
pub fn enforce(ruleset: BuiltRuleset, policy: &SandboxPolicy) -> Result<()> {
    #[cfg(target_os = "linux")]
    {
        linux::enforce(ruleset, policy)
    }

    #[cfg(not(target_os = "linux"))]
    {
        let _ = (ruleset, policy);
        Ok(())
    }
