// SAFETY: pre_exec runs after fork but before exec in the child process.
        // setpgid and setns are async-signal-safe and safe to call in this context.
        {
            let policy = policy.clone();
            let workdir = workdir.map(str::to_string);
            #[allow(unsafe_code)]
            unsafe {
                cmd.pre_exec(move || {
                    if !interactive {
                        // Create new process group
                        libc::setpgid(0, 0);
                    }

                    // Enter network namespace before applying other restrictions
                    if let Some(fd) = netns_fd {
                        let result = libc::setns(fd, libc::CLONE_NEWNET);
                        if result != 0 {
                            return Err(std::io::Error::last_os_error());
                        }
                    }

                    // Phase 1: Build Landlock ruleset as root (opens O_PATH FDs,
                    // creates the ruleset, adds rules). Must happen before
                    // drop_privileges so path FDs can be opened.
                    let landlock_ruleset = sandbox::build_ruleset(&policy, workdir.as_deref())
                        .map_err(|err| std::io::Error::other(err.to_string()))?;

                    // Drop privileges: initgroups/setgid/setuid need access to
                    // /etc/group and /etc/passwd, which must be done before
                    // Landlock enforcement (which would block those paths).
                    drop_privileges(&policy)
                        .map_err(|err| std::io::Error::other(err.to_string()))?;

                    // Phase 2: Enforce Landlock (restrict_self) and apply
                    // seccomp. Landlock is enforced after privilege drop so the
                    // unprivileged process is restricted.
                    if let Some(ruleset) = landlock_ruleset {
                        sandbox::enforce(ruleset, &policy)
                            .map_err(|err| std::io::Error::other(err.to_string()))?;
                    }

                    Ok(())
                });
            }
        }

