// SPDX-FileCopyrightText: Copyright (c) 2025-2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
// SPDX-License-Identifier: Apache-2.0

//! Landlock filesystem sandboxing.

use crate::policy::{LandlockCompatibility, SandboxPolicy};
use landlock::{
    ABI, Access, AccessFs, CompatLevel, Compatible, PathBeneath, PathFd, PathFdError, Ruleset,
    RulesetAttr, RulesetCreated, RulesetCreatedAttr,
};
use miette::{IntoDiagnostic, Result};
use std::path::{Path, PathBuf};
use tracing::debug;

/// A Landlock ruleset that has been built (paths opened, rules added) but not
/// yet enforced via `restrict_self()`. The caller must call [`enforce`] to
/// activate the restrictions.
///
/// This split allows opening path FDs as root (before privilege drop) and
/// enforcing the ruleset afterward (after privilege drop).
pub struct BuiltRuleset {
    ruleset: RulesetCreated,
    compatibility: LandlockCompatibility,
}

impl BuiltRuleset {
    /// Enforce this Landlock ruleset on the current thread via `restrict_self()`.
    ///
    /// On failure in `BestEffort` mode, logs an OCSF finding and prints a
    /// visible warning to stderr before returning `Ok(())`.
    pub fn enforce(self) -> Result<()> {
        let result = self.ruleset.restrict_self().into_diagnostic();
        if let Err(err) = result {
            if matches!(self.compatibility, LandlockCompatibility::BestEffort) {
                eprintln!(
                    "WARNING: Landlock filesystem sandbox is NOT active: {err}. \
                     Set landlock.compatibility to 'hard_requirement' to make this fatal."
                );
                openshell_ocsf::ocsf_emit!(
                    openshell_ocsf::DetectionFindingBuilder::new(crate::ocsf_ctx())
                        .activity(openshell_ocsf::ActivityId::Open)
                        .severity(openshell_ocsf::SeverityId::High)
                        .confidence(openshell_ocsf::ConfidenceId::High)
                        .is_alert(true)
                        .finding_info(
                            openshell_ocsf::FindingInfo::new(
                                "landlock-unavailable",
                                "Landlock Filesystem Sandbox Unavailable",
                            )
                            .with_desc(&format!(
                                "Running WITHOUT filesystem restrictions: {err}. \
                                 Set landlock.compatibility to 'hard_requirement' to make this fatal."
                            )),
                        )
                        .message(format!("Landlock filesystem sandbox unavailable: {err}"))
                        .build()
                );
                return Ok(());
            }
            return Err(err);
        }
        Ok(())
    }
}

/// Build a Landlock ruleset by opening path FDs and adding rules.
///
/// This opens `O_PATH` FDs and calls `landlock_create_ruleset` — both must be
/// done while the process still has sufficient privileges (typically as root).
/// Call [`BuiltRuleset::enforce`] afterward to activate the restrictions.
///
