   132	            if let Some(path_fd) = try_open_path(path, &compatibility)? {
   133	                debug!(path = %path.display(), "Landlock allow read-write");
   134	                ruleset = ruleset
   135	                    .add_rule(PathBeneath::new(path_fd, access_all))
   136	                    .into_diagnostic()?;
