   204	/// [`BuiltRuleset::enforce`]. Prefer the two-phase API ([`build_ruleset`] +
   205	/// [`BuiltRuleset::enforce`]) in `pre_exec` hooks so that path FDs can be
   206	/// opened before dropping privileges.
   207	pub fn apply(policy: &SandboxPolicy, workdir: Option<&str>) -> Result<()> {
   208	    if let Some(ruleset) = build_ruleset(policy, workdir)? {
   209	        ruleset.enforce()?;
   210	    }
   211	    Ok(())
   212	}
   213	
   214	/// Attempt to open a path for Landlock rule creation.
   215	///
   216	/// In `BestEffort` mode, inaccessible paths (missing, permission denied, symlink
   217	/// loops, etc.) are skipped with a warning and `Ok(None)` is returned so the
   218	/// caller can continue building the ruleset from the remaining valid paths.
   219	///
   220	/// In `HardRequirement` mode, any failure is fatal — the caller propagates the
   221	/// error, which ultimately aborts sandbox startup.
   222	fn try_open_path(path: &Path, compatibility: &LandlockCompatibility) -> Result<Option<PathFd>> {
   223	    match PathFd::new(path) {
   224	        Ok(fd) => Ok(Some(fd)),
   225	        Err(err) => {
   226	            let reason = classify_path_fd_error(&err);
   227	            let is_not_found = matches!(
   228	                &err,
   229	                PathFdError::OpenCall { source, .. }
   230	                    if source.kind() == std::io::ErrorKind::NotFound
   231	            );
