   233	                LandlockCompatibility::BestEffort => {
   234	                    // NotFound is expected for stale baseline paths (e.g.
   235	                    // /app baked into the server-stored policy but absent
   236	                    // in this container image).  Log at debug! to avoid
   237	                    // polluting SSH exec stdout — the pre_exec hook
   238	                    // inherits the tracing subscriber whose writer targets
   239	                    // fd 1 (the pipe/PTY).
   240	                    //
   241	                    // Other errors (permission denied, symlink loops, etc.)
   242	                    // are genuinely unexpected and logged at warn!.
   243	                    if is_not_found {
   244	                        debug!(
   245	                            path = %path.display(),
   246	                            reason,
   247	                            "Skipping non-existent Landlock path (best-effort mode)"
   248	                        );
   249	                    } else {
   250	                        openshell_ocsf::ocsf_emit!(
   251	                            openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
   252	                                .severity(openshell_ocsf::SeverityId::Medium)
   253	                                .status(openshell_ocsf::StatusId::Failure)
   254	                                .state(openshell_ocsf::StateId::Other, "degraded")
   255	                                .message(format!(
   256	                                    "Skipping inaccessible Landlock path (best-effort) [path:{} error:{err}]",
   257	                                    path.display()
   258	                                ))
   259	                                .build()
   260	                        );
   261	                    }
   262	                    Ok(None)
   263	                }
   264	                LandlockCompatibility::HardRequirement => Err(miette::miette!(
   265	                    "Landlock path unavailable in hard_requirement mode: {} ({}): {}",
   266	                    path.display(),
   267	                    reason,
   268	                    err,
   269	                )),
   270	            }
   271	        }
   272	    }
   273	}
   274	
   275	/// Classify a [`PathFdError`] into a human-readable reason.
   276	///
   277	/// `PathFd::new()` wraps `open(path, O_PATH | O_CLOEXEC)` which can fail for
   278	/// several reasons beyond simple non-existence. The `PathFdError::OpenCall`
   279	/// variant wraps the underlying `std::io::Error`.
   280	fn classify_path_fd_error(err: &PathFdError) -> &'static str {
   281	    match err {
   282	        PathFdError::OpenCall { source, .. } => classify_io_error(source),
   283	        // PathFdError is #[non_exhaustive], handle future variants gracefully.
   284	        _ => "unexpected error",
   285	    }
   286	}
   287	
   288	/// Classify a `std::io::Error` into a human-readable reason string.
   289	fn classify_io_error(err: &std::io::Error) -> &'static str {
   290	    match err.kind() {
   291	        std::io::ErrorKind::NotFound => "path does not exist",
   292	        std::io::ErrorKind::PermissionDenied => "permission denied",
   293	        _ => match err.raw_os_error() {
   294	            Some(40) => "too many symlink levels",           // ELOOP
   295	            Some(36) => "path name too long",                // ENAMETOOLONG
   296	            Some(20) => "path component is not a directory", // ENOTDIR
   297	            _ => "unexpected error",
   298	        },
   299	    }
   300	}
   301	
   302	fn compat_level(level: &LandlockCompatibility) -> CompatLevel {
   303	    match level {
   304	        LandlockCompatibility::BestEffort => CompatLevel::BestEffort,
   305	        LandlockCompatibility::HardRequirement => CompatLevel::HardRequirement,
   306	    }
   307	}
   308	
   309	#[cfg(test)]
   310	mod tests {
   311	    use super::*;
   312	
   313	    #[test]
   314	    fn try_open_path_best_effort_returns_none_for_missing_path() {
   315	        let result = try_open_path(
   316	            &PathBuf::from("/nonexistent/openshell/test/path"),
   317	            &LandlockCompatibility::BestEffort,
   318	        );
   319	        assert!(result.is_ok());
   320	        assert!(result.unwrap().is_none());
   321	    }
   322	
   323	    #[test]
   324	    fn try_open_path_hard_requirement_errors_for_missing_path() {
